query:
query ConversationModelStatuses($input: ConversationListModelAvailabilityRequestInput!) @component(name: "Workspace.Assistant") {
  conversationListModelAvailability(input: $input) {
    modelAvailability {
      clientId
      modelStatuses {
        isAvailable
        name
        status
        __typename
      }
      __typename
    }
    apiError {
      code
      message
      __typename
    }
    __typename
  }
}
